BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?edge ?source ?target ?edgeName ?sourceName ?targetName WHERE {
  ?activity vocab:NamedElement_name "Acquire%20and%20Guide" .
  ?activity vocab:Activity_edge ?edge .
  OPTIONAL { ?edge vocab:ActivityEdge_source ?source . }
  OPTIONAL { ?edge vocab:ActivityEdge_target ?target . }
  OPTIONAL { ?edge vocab:NamedElement_name ?edgeName . }
  OPTIONAL { ?source vocab:NamedElement_name ?sourceName . }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName . }
}
LIMIT 50

